blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie nauczysz się tworzyć <strong>stan bierny z czasownikami modalnymi</strong>: może, musi, powinien, może, może, mógłby. Podstawowa formuła: <strong>modalny + be + V3</strong>.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "<strong>modalne + być + V3</strong>:",
            "example": "It must be done today."
        },
        {
            "label": "Możliwość",
            "color": "blue",
            "text": "<strong>może/może + być + V3</strong>:",
            "example": "This can be fixed easily."
        },
        {
            "label": "Konieczność",
            "color": "rose",
            "text": "<strong>musi/powinno + być + V3</strong>:",
            "example": "The rules must be followed."
        }
    ]
}

{
    "title": "1. Podstawowa struktura Modalnej Pasywności",
    "intro": "Strona bierna z czasownikami modalnymi zawsze używa <strong>modal + be + V3</strong>:",
    "items": [
        {
            "label": "Formuła",
            "title": "modalne + być + V3",
            "subtitle": "be występuje zawsze w bezokoliczniku, V3 jest trzecią formą czasownika"
        },
        {
            "label": "Bez tego",
            "title": "Bez cząstki do",
            "subtitle": "Po czasownikach modalnych be następuje bez to"
        },
        {
            "label": "Bez zmian V3",
            "title": "V3 się nie zmienia",
            "subtitle": "Imiesłów bierny występuje zawsze w jednej formie"
        },
        {
            "label": "Wszystkie tematy",
            "title": "Dla wszystkich przedmiotów",
            "subtitle": "Struktura jest taka sama dla Ja/on/oni"
        }
    ]
}

{
    "title": "2. Może/mógłby + być + V3 (możliwość, zdolność)",
    "sections": [
        {
            "label": "może być + V3",
            "color": "emerald",
            "description": "<strong>Możliwość</strong> lub <strong>możliwość</strong> bycia działaniem. Obecny.",
            "examples": [
                {
                    "en": "This problem can be solved easily.",
                    "ua": "Ten problem można łatwo rozwiązać."
                },
                {
                    "en": "The document can be downloaded from the website.",
                    "ua": "Dokument można pobrać ze strony."
                },
                {
                    "en": "English can be learned online.",
                    "ua": "Możesz uczyć się angielskiego online."
                }
            ]
        },
        {
            "label": "może być + V3",
            "color": "sky",
            "description": "<strong>Możliwość warunkowa</strong> lub możliwość w przeszłości.",
            "examples": [
                {
                    "en": "The work could be finished tomorrow.",
                    "ua": "Prace mogłyby zakończyć się jutro."
                },
                {
                    "en": "This issue could be resolved with more time.",
                    "ua": "Ten problem można rozwiązać, jeśli potrzeba więcej czasu."
                },
                {
                    "en": "The building could be seen from far away.",
                    "ua": "Budynek był widoczny z daleka."
                }
            ]
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "description": "<strong>nie może (nie może) / nie mógł (nie mógł) + być + V3</strong>",
            "examples": [
                {
                    "en": "This error cannot be fixed.",
                    "ua": "Tego błędu nie można naprawić."
                },
                {
                    "en": "The package couldn't be delivered.",
                    "ua": "Przesyłka nie mogła zostać dostarczona."
                }
            ]
        }
    ]
}

{
    "title": "3. Musi/musi + być + V3 (konieczność)",
    "sections": [
        {
            "label": "musi być + V3",
            "color": "rose",
            "description": "<strong>Silna konieczność</strong> lub obowiązek. Porządek, rządź.",
            "examples": [
                {
                    "en": "This task must be done today.",
                    "ua": "To zadanie musi zostać wykonane dzisiaj."
                },
                {
                    "en": "The rules must be followed.",
                    "ua": "Należy przestrzegać zasad."
                },
                {
                    "en": "All documents must be signed.",
                    "ua": "Wszystkie dokumenty muszą zostać podpisane."
                }
            ]
        },
        {
            "label": "musi / musi być + V3",
            "color": "amber",
            "description": "Konieczność wynikająca z okoliczności zewnętrznych. <strong>muszę</strong> ma formy w różnych czasach.",
            "examples": [
                {
                    "en": "The work has to be finished by Friday.",
                    "ua": "Prace powinny zakończyć się do piątku."
                },
                {
                    "en": "The application had to be submitted yesterday.",
                    "ua": "Wniosek powinien był zostać złożony już wczoraj."
                }
            ]
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "description": "<strong>nie wolno (nie wolno)</strong> jest zakazem. <strong>nie musi</strong> — niekoniecznie.",
            "examples": [
                {
                    "en": "This button must not be pressed.",
                    "ua": "Tego przycisku nie można nacisnąć. (zakaz)"
                },
                {
                    "en": "The report doesn't have to be submitted today.",
                    "ua": "Raportu nie trzeba składać dzisiaj."
                }
            ]
        }
    ]
}

{
    "title": "4. Powinno/powinno + być + V3 (rekomendacja)",
    "sections": [
        {
            "label": "powinno być + V3",
            "color": "blue",
            "description": "<strong>Rada</strong> lub <strong>rekomendacja</strong>. Co jest słuszne i pożądane.",
            "examples": [
                {
                    "en": "The report should be checked before submission.",
                    "ua": "Sprawozdanie należy sprawdzić przed złożeniem."
                },
                {
                    "en": "These instructions should be followed carefully.",
                    "ua": "Należy dokładnie przestrzegać tych instrukcji."
                },
                {
                    "en": "Mistakes should be corrected immediately.",
                    "ua": "Błędy należy natychmiast poprawić."
                }
            ]
        },
        {
            "label": "powinno być + V3",
            "color": "sky",
            "description": "Tak samo jak <strong>powinno</strong>, ale bardziej formalnie. Rzadko używany.",
            "examples": [
                {
                    "en": "The project ought to be completed soon.",
                    "ua": "Projekt powinien wkrótce zostać ukończony."
                }
            ]
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "description": "<strong>nie powinno (nie powinno) + być + V3</strong>",
            "examples": [
                {
                    "en": "This information should not be shared.",
                    "ua": "Tych informacji nie należy udostępniać."
                },
                {
                    "en": "The door shouldn't be left open.",
                    "ua": "Drzwi nie powinny pozostać otwarte."
                }
            ]
        }
    ]
}

{
    "title": "5. Może/może + być + V3 (prawdopodobieństwo, zezwolenie)",
    "sections": [
        {
            "label": "może być + V3",
            "color": "amber",
            "description": "<strong>Prawdopodobieństwo</strong> (możliwe) lub <strong>zezwolenie</strong> (formalne).",
            "examples": [
                {
                    "en": "The package may be delivered today.",
                    "ua": "Przesyłka może zostać dostarczona jeszcze dzisiaj."
                },
                {
                    "en": "This issue may be discussed at the meeting.",
                    "ua": "Temat ten może zostać omówiony na spotkaniu."
                },
                {
                    "en": "Photos may be taken during the event.",
                    "ua": "Podczas wydarzenia można wykonać zdjęcia. (dozwolony)"
                }
            ]
        },
        {
            "label": "może być + V3",
            "color": "sky",
            "description": "Mniej prawdopodobne niż <strong>może</strong>. „Możliwe, ale mało prawdopodobne”.",
            "examples": [
                {
                    "en": "The project might be postponed.",
                    "ua": "Projekt może się opóźnić."
                },
                {
                    "en": "The error might be caused by the update.",
                    "ua": "Błąd może być spowodowany aktualizacją."
                }
            ]
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "description": "<strong>może nie / może nie + być + V3</strong>",
            "examples": [
                {
                    "en": "The results may not be ready yet.",
                    "ua": "Wyniki mogą nie być jeszcze gotowe."
                }
            ]
        }
    ]
}

{
    "title": "6. Pytania z modami w stronie biernej",
    "sections": [
        {
            "label": "Pytanie Tak/Nie",
            "color": "blue",
            "description": "<strong>Modalne + S + be + V3?</strong>",
            "examples": [
                {
                    "en": "Can this problem be solved?",
                    "ua": "Czy można rozwiązać ten problem?"
                },
                {
                    "en": "Must the task be done today?",
                    "ua": "Czy zadanie jest oddane na dzisiaj?"
                },
                {
                    "en": "Should the report be submitted now?",
                    "ua": "Czy raport należy złożyć teraz?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Jakie-słowo + modalne + S + be + V3?</strong>",
            "examples": [
                {
                    "en": "How can this be fixed?",
                    "ua": "Jak można to naprawić?"
                },
                {
                    "en": "When should the work be finished?",
                    "ua": "Kiedy prace powinny zostać zakończone?"
                },
                {
                    "en": "Where must the documents be signed?",
                    "ua": "Gdzie należy podpisać dokumenty?"
                }
            ]
        }
    ]
}

{
    "title": "7. Koniugacja modali w stronie biernej",
    "intro": "Główne czasowniki modalne ze stanem biernym:",
    "rows": [
        {
            "en": "can be + V3",
            "ua": "możliwość",
            "note": "This can be done easily."
        },
        {
            "en": "could be + V3",
            "ua": "możliwość warunkowa",
            "note": "It could be finished tomorrow."
        },
        {
            "en": "must be + V3",
            "ua": "silna konieczność",
            "note": "It must be done now."
        },
        {
            "en": "should be + V3",
            "ua": "zalecenie",
            "note": "It should be checked."
        },
        {
            "en": "may be + V3",
            "ua": "prawdopodobieństwo, pozwolenie",
            "note": "It may be delayed."
        },
        {
            "en": "might be + V3",
            "ua": "mniej prawdopodobne",
            "note": "It might be cancelled."
        }
    ]
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Używanie tego, co było wcześniej.",
            "wrong": "It must to be done.",
            "right": "✅ It must be done."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Niepoprawna forma bycia.",
            "wrong": "It can is done.",
            "right": "✅ It can be done."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Używanie V1 zamiast V3.",
            "wrong": "It should be do.",
            "right": "✅ It should be done."
        }
    ]
}
